+import { object } from "./constructs.ts";
+import { formatMessage } from "./message.ts";
+import { withDefault } from "./modifiers.ts";
+import { parseSync, suggestSync } from "./parser.ts";
+import { conditionalOption, option, optionalWhen, requiredWhen } from "./primitives.ts";
+import { choice, string } from "./valueparser.ts";
+import assert from "node:assert/strict";
+import { describe, it } from "node:test";
+
+describe("conditional options", () => {
+  it("maps a CLI flag condition through a wrapped parser", () => {
+    const parser = object({
+      mode: withDefault(option("--mode", choice(["dev", "prod"])), "dev"),
+      token: requiredWhen({ option: "--mode", value: "prod" }, "--token", string()),
+    });
+
+    const result = parseSync(parser, ["--token", "secret"]);
+    assert.ok(!result.success);
+    if (!result.success) {
+      const error = formatMessage(result.error);
+      assert.ok(error.includes("requires option"));
+      assert.ok(error.includes("--mode"));
+      assert.ok(error.includes("prod"));
+    }
+  });
+
+  it("supports object keys, compound conditions, and empty groups", () => {
+    const parser = object({
+      enabled: option("--enabled"),
+      mode: option("--mode", choice(["a", "b"])),
+      value: requiredWhen({
+        allOf: [{ option: "enabled" }, { option: "mode", value: "a" }],
+      }, "--value", string()),
+      always: requiredWhen({ allOf: [] }, "--always", string()),
+      never: optionalWhen({ anyOf: [] }, "--never", string()),
+    });
+
+    assert.ok(parseSync(parser, ["--enabled", "--mode", "a", "--value", "x"]).success);
+    assert.ok(parseSync(parser, ["--always", "x"]).success);
+    assert.ok(parseSync(parser, ["--never", "x"]).success);
+    assert.deepEqual(
+      suggestSync(parser, ["--"] as [string]),
+      [],
+    );
+  });
+
+  it("hides optional conditions but rejects an explicit falsy dependee", () => {
+    const parser = object({
+      enabled: option("--enabled", choice(["true", "false"])),
+      extra: optionalWhen("enabled", "--extra", string()),
+    });
+    assert.deepEqual(suggestSync(parser, ["--"] as [string]), []);
+    assert.ok(parseSync(parser, ["--extra", "ok"]).success);
+
+    const result = parseSync(parser, ["--enabled", "false", "--extra", "no"]);
+    assert.ok(!result.success);
+  });
+
+  it("accepts a full dependsOn configuration", () => {
+    const parser = object({
+      enabled: option("--enabled"),
+      output: conditionalOption(
+        { option: "enabled", required: true },
+        "--output",
+        string(),
+      ),
+    });
+    assert.ok(!parseSync(parser, ["--output", "x"]).success);
+  });
+});
